import { Component, Input, OnInit, OnChanges, DoCheck, AfterContentInit, AfterViewInit, OnDestroy, SimpleChanges } from '@angular/core';

@Component({
  selector: 'app-demo',
  standalone: true,
  template: `<p>{{ label }}</p><ng-content></ng-content>`
})
export class DemoComponent
  implements OnChanges, OnInit, DoCheck, AfterContentInit, AfterViewInit, OnDestroy {

  @Input() label = '';

  ngOnChanges(changes: SimpleChanges): void {
    // Runs first, and on every @Input reference change.
    console.log('ngOnChanges', changes);
  }

  ngOnInit(): void {
    // Inputs are now set. Safe place for input-dependent init.
    console.log('ngOnInit, label =', this.label);
  }

  ngDoCheck(): void {
    // Every CD pass. Keep this cheap.
  }

  ngAfterContentInit(): void {
    // Projected content (ContentChild) is available.
  }

  ngAfterViewInit(): void {
    // The view and child views (ViewChild) are available.
  }

  ngOnDestroy(): void {
    // Final cleanup.
  }
}

