import { Component, Input, OnChanges, SimpleChanges } from '@angular/core';

@Component({ selector: 'app-price', standalone: true, template: '{{ formatted }}' })
export class PriceComponent implements OnChanges {
  @Input() amount = 0;
  @Input() currency = 'USD';
  formatted = '';

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['amount']) {
      const c = changes['amount'];
      console.log('amount', c.previousValue, '->', c.currentValue, 'first?', c.firstChange);
    }
    // Recompute derived state whenever any relevant input changes.
    if (changes['amount'] || changes['currency']) {
      this.formatted = new Intl.NumberFormat('en-US', {
        style: 'currency',
        currency: this.currency
      }).format(this.amount);
    }
  }
}

import { Component, input, computed } from '@angular/core';

@Component({ selector: 'app-price', standalone: true, template: '{{ formatted() }}' })
export class PriceComponent {
  amount = input(0);
  currency = input('USD');

  // Recomputes automatically when either input changes. No ngOnChanges needed.
  formatted = computed(() =>
    new Intl.NumberFormat('en-US', { style: 'currency', currency: this.currency() })
