import { Component, ViewChild, ContentChild, ElementRef, AfterViewInit, AfterContentInit } from '@angular/core';

@Component({
  selector: 'app-panel',
  standalone: true,
  template: `<div #box>...</div><ng-content></ng-content>`
})
export class PanelComponent implements AfterContentInit, AfterViewInit {
  @ViewChild('box') box?: ElementRef<HTMLDivElement>;
  @ContentChild(HeaderComponent) header?: HeaderComponent;

  ngAfterContentInit(): void {
    // header is resolved here (projected content).
    console.log('projected header:', this.header);
  }

  ngAfterViewInit(): void {
    // box is resolved here (own view). Reading it in ngOnInit would be undefined.
    console.log('box width:', this.box?.nativeElement.offsetWidth);
  }
}

import { Component, ElementRef, afterNextRender, afterRender, inject } from '@angular/core';

@Component({ selector: 'app-measure', standalone: true, template: '<div>content</div>' })
export class MeasureComponent {
  private readonly host = inject(ElementRef);

  constructor() {
    // Runs once after the first render. DOM is available; safe on SSR (skipped on server).
    afterNextRender(() => {
      const width = this.host.nativeElement.offsetWidth;
      console.log('initial width', width);
    });

    // Runs after every render. Keep it cheap.
    afterRender(() => {
      // e.g., sync a canvas size to its container.
    });
  }
}

import { Component, inject, DestroyRef } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { interval } from 'rxjs';

@Component({ selector: 'app-clock', standalone: true, template: '{{ tick }}' })
export class ClockComponent {
  tick = 0;
  private readonly destroyRef = inject(DestroyRef);

  constructor() {
    // takeUntilDestroyed reads DestroyRef from the current injection context.
    interval(1000)
      .pipe(takeUntilDestroyed())
      .subscribe(v => (this.tick = v));

    // DestroyRef also lets you register imperative teardown callbacks.
    this.destroyRef.onDestroy(() => console.log('component destroyed'));
  }
}

