import { Component, input, effect, signal } from '@angular/core';

@Component({ selector: 'app-status', standalone: true, template: '{{ label() }}' })
export class StatusComponent {
  online = input(false);
  label = signal('unknown');

  constructor() {
    // Replaces an ngOnChanges branch: runs whenever `online` changes.
    effect(() => {
      this.label.set(this.online() ? 'Online' : 'Offline');
    });
  }
}

import {
  Component, ElementRef, input, effect, afterNextRender,
  inject, DestroyRef, viewChild
} from '@angular/core';
import Chart from 'chart.js/auto';

@Component({
  selector: 'app-sales-chart',
  standalone: true,
  template: '<canvas #canvas></canvas>'
})
export class SalesChartComponent {
  data = input<number[]>([]);
  private readonly canvasRef = viewChild<ElementRef<HTMLCanvasElement>>('canvas');
  private readonly destroyRef = inject(DestroyRef);
  private chart?: Chart;

  constructor() {
    // Initialize once, after the browser has rendered the canvas. Skipped on SSR.
    afterNextRender(() => {
      const el = this.canvasRef()?.nativeElement;
      if (!el) return;
      this.chart = new Chart(el, {
        type: 'line',
        data: { labels: [], datasets: [{ label: 'Sales', data: this.data() }] }
      });
    });

    // Push new data into the existing chart when the input signal changes.
    effect(() => {
      const values = this.data();
      if (this.chart) {
        this.chart.data.datasets[0].data = values;
        this.chart.update();
      }
    });

    // Deterministic cleanup: release the chart when the component is destroyed.
    this.destroyRef.onDestroy(() => this.chart?.destroy());
  }
}

import {
  Component, Input, OnChanges, OnInit, AfterViewInit, OnDestroy,
  SimpleChanges, ViewChild, ElementRef, inject, DestroyRef
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { fromEvent } from 'rxjs';

@Component({
  selector: 'app-editor',
  standalone: true,
  template: '<textarea #area></textarea>'
})
export class EditorComponent implements OnChanges, OnInit, AfterViewInit, OnDestroy {
  @Input() value = '';
  @ViewChild('area') area?: ElementRef<HTMLTextAreaElement>;
  private readonly destroyRef = inject(DestroyRef);

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['value'] && this.area) {
      this.area.nativeElement.value = this.value;
    }
  }

  ngOnInit(): void {
    // value input is set; safe to use for initial state decisions.
  }

  ngAfterViewInit(): void {
    const el = this.area!.nativeElement;
    el.value = this.value;
    fromEvent(el, 'input')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => console.log('changed', el.value));
  }

  ngOnDestroy(): void {
    // takeUntilDestroyed already handles the subscription; extra teardown here if needed.
  }
}

